import React, { useState } from 'react';
import { ArrowLeft, Book, Heart, Users, Coffee, Smile, Share2, Search, Quote, ChevronRight, Star, AlertCircle, Droplet, Sun, Moon, Shield, BookOpen, GraduationCap, Home, X, ScrollText } from 'lucide-react';

interface HadithItem {
  arabic: string;
  text: string;
  source: string;
}

interface Topic {
  id: string;
  title: string;
  icon: React.ElementType;
  description: string;
  hadiths: HadithItem[];
}

const TOPICS: Topic[] = [
  {
    id: 'nawawi',
    title: "Les 40 Hadiths an-Nawawi",
    icon: ScrollText,
    description: "Les fondements de l'Islam rassemblés par l'Imam An-Nawawi",
    hadiths: [
      {
        arabic: "إِنَّمَا الْأَعْمَالُ بِالنِّيَّاتِ، وَإِنَّمَا لِكُلِّ امْرِئٍ مَا نَوَى",
        text: "Les actes ne valent que par les intentions, et à chacun selon son intention. Celui dont l'émigration est pour Allah et Son Messager, son émigration est pour Allah et Son Messager...",
        source: "Hadith 1 - Bukhari & Muslim"
      },
      {
        arabic: "بَيْنَمَا نَحْنُ جُلُوسٌ عِنْدَ رَسُولِ اللَّهِ ﷺ ذَاتَ يَوْمٍ، إِذْ طَلَعَ عَلَيْنَا رَجُلٌ شَدِيدُ بَيَاضِ الثِّيَابِ، شَدِيدُ سَوَادِ الشَّعْرِ...",
        text: "L'Islam, c'est que tu témoignes qu'il n'y a de divinité qu'Allah et que Muhammad est le Messager d'Allah... La Foi (Iman), c'est que tu croies en Allah, en Ses Anges, en Ses Livres...",
        source: "Hadith 2 - Muslim"
      },
      {
        arabic: "بُنِيَ الْإِسْلَامُ عَلَى خَمْسٍ: شَهَادَةِ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا رَسُولُ اللَّهِ، وَإِقَامِ الصَّلَاةِ، وَإِيتَاءِ الزَّكَاةِ، وَحَجِّ الْبَيْتِ، وَصَوْمِ رَمَضَانَ",
        text: "L'Islam est bâti sur cinq piliers : L'attestation qu'il n'y a de divinité qu'Allah et que Muhammad est Son Messager, l'accomplissement de la prière, l'acquittement de la Zakat, le Hajj et le jeûne du Ramadan.",
        source: "Hadith 3 - Bukhari & Muslim"
      },
      {
        arabic: "إِنَّ أَحَدَكُمْ يُجْمَعُ خَلْقُهُ فِي بَطْنِ أُمِّهِ أَرْبَعِينَ يَوْمًا نُطْفَةً...",
        text: "La création de chacun d'entre vous est réunie dans le ventre de sa mère... Puis l'ange lui est envoyé et il lui insuffle l'esprit.",
        source: "Hadith 4 - Bukhari & Muslim"
      },
      {
        arabic: "مَنْ أَحْدَثَ فِي أَمْرِنَا هَذَا مَا لَيْسَ مِنْهُ فَهُوَ رَدٌّ",
        text: "Celui qui innove dans notre affaire-ci (l'Islam) ce qui n'en fait pas partie, cela lui sera rejeté.",
        source: "Hadith 5 - Bukhari & Muslim"
      },
      {
        arabic: "إِنَّ الْحَلَالَ بَيِّنٌ، وَإِنَّ الْحَرَامَ بَيِّنٌ، وَبَيْنَهُمَا مُشْتَبِهَاتٌ لَا يَعْلَمُهُنَّ كَثِيرٌ مِنَ النَّاسِ",
        text: "Certes, le licite est clair et l'illicite est clair, et entre les deux se trouvent des choses douteuses... Celui qui se préserve des choses douteuses a préservé sa religion et son honneur.",
        source: "Hadith 6 - Bukhari & Muslim"
      },
      {
        arabic: "الدِّينُ النَّصِيحَةُ. قُلْنَا: لِمَنْ؟ قَالَ: لِلَّهِ وَلِكِتَابِهِ وَلِرَسُولِهِ وَلِأَئِمَّةِ الْمُسْلِمِينَ وَعَامَّتِهِمْ",
        text: "La religion, c'est le bon conseil (la sincérité). Nous dîmes : 'Envers qui ?' Il dit : 'Envers Allah, Son Livre, Son Messager, les dirigeants des musulmans et le commun des musulmans.'",
        source: "Hadith 7 - Muslim"
      },
      {
        arabic: "أُمِرْتُ أَنْ أُقَاتِلَ النَّاسَ حَتَّى يَشْهَدُوا أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا رَسُولُ اللَّهِ...",
        text: "Il m'a été ordonné de combattre les gens jusqu'à ce qu'ils attestent qu'il n'y a de divinité qu'Allah et que Muhammad est le Messager d'Allah...",
        source: "Hadith 8 - Bukhari & Muslim"
      },
      {
        arabic: "مَا نَهَيْتُكُمْ عَنْهُ فَاجْتَنِبُوهُ، وَمَا أَمَرْتُكُمْ بِهِ فَأْتُوا مِنْهُ مَا اسْتَطَعْتُمْ",
        text: "Ce que je vous ai interdit, évitez-le ; et ce que je vous ai ordonné, accomplissez-en ce que vous pouvez.",
        source: "Hadith 9 - Bukhari & Muslim"
      },
      {
        arabic: "إِنَّ اللَّهَ طَيِّبٌ لَا يَقْبَلُ إِلَّا طَيِّبًا",
        text: "Allah est Bon et n'accepte que ce qui est bon. Et Allah a ordonné aux croyants ce qu'Il a ordonné aux Messagers.",
        source: "Hadith 10 - Muslim"
      },
      {
        arabic: "دَعْ مَا يَرِيبُكَ إِلَى مَا لَا يَرِيبُكَ",
        text: "Laisse ce qui te jette dans le doute pour ce qui ne t'y jette pas.",
        source: "Hadith 11 - Tirmidhi"
      },
      {
        arabic: "مِنْ حُسْنِ إِسْلَامِ الْمَرْءِ تَرْكُهُ مَا لَا يَعْنِيهِ",
        text: "Fait partie du bel Islam d'une personne de délaisser ce qui ne la regarde pas.",
        source: "Hadith 12 - Tirmidhi"
      },
      {
        arabic: "لَا يُؤْمِنُ أَحَدُكُمْ حَتَّى يُحِبَّ لِأَخِيهِ مَا يُحِبُّ لِنَفْسِهِ",
        text: "Aucun de vous ne sera (parfaitement) croyant tant qu'il n'aimera pas pour son frère ce qu'il aime pour lui-même.",
        source: "Hadith 13 - Bukhari & Muslim"
      },
      {
        arabic: "لَا يَحِلُّ دَمُ امْرِئٍ مُسْلِمٍ... إِلَّا بِإِحْدَى ثَلَاثٍ",
        text: "Il n'est pas permis de verser le sang d'un musulman... sauf dans trois cas : le marié qui commet l'adultère, vie pour vie, et celui qui délaisse sa religion.",
        source: "Hadith 14 - Bukhari & Muslim"
      },
      {
        arabic: "مَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيَقُلْ خَيْرًا أَوْ لِيَصْمُتْ",
        text: "Que celui qui croit en Allah et au Jour Dernier dise du bien ou qu'il se taise. Et que celui qui croit en Allah et au Jour Dernier honore son voisin.",
        source: "Hadith 15 - Bukhari & Muslim"
      },
      {
        arabic: "لَا تَغْضَبْ",
        text: "Un homme dit au Prophète : 'Conseille-moi'. Il dit : 'Ne te mets pas en colère'. L'homme répéta plusieurs fois, et il dit : 'Ne te mets pas en colère'.",
        source: "Hadith 16 - Bukhari"
      },
      {
        arabic: "إِنَّ اللَّهَ كَتَبَ الْإِحْسَانَ عَلَى كُلِّ شَيْءٍ",
        text: "Certes Allah a prescrit l'excellence (Ihsan) en toute chose. Si vous tuez, tuez bien. Si vous égorgez, égorgez bien.",
        source: "Hadith 17 - Muslim"
      },
      {
        arabic: "اتَّقِ اللَّهَ حَيْثُمَا كُنْتَ، وَأَتْبِعِ السَّيِّئَةَ الْحَسَنَةَ تَمْحُهَا، وَخَالِقِ النَّاسَ بِخُلُقٍ حَسَنٍ",
        text: "Crains Allah où que tu sois. Fais suivre la mauvaise action par une bonne, elle l'effacera. Et comporte-toi avec les gens avec un bon caractère.",
        source: "Hadith 18 - Tirmidhi"
      },
      {
        arabic: "احْفَظِ اللَّهَ يَحْفَظْكَ، احْفَظِ اللَّهَ تَجِدْهُ تُجَاهَكَ",
        text: "Préserve Allah, Il te préservera. Préserve Allah, tu Le trouveras devant toi. Si tu demandes, demande à Allah. Si tu cherches l'aide, cherche-la auprès d'Allah.",
        source: "Hadith 19 - Tirmidhi"
      },
      {
        arabic: "إِنَّ مِمَّا أَدْرَكَ النَّاسُ مِنْ كَلَامِ النُّبُوَّةِ الْأُولَى: إِذَا لَمْ تَسْتَحِ فَاصْنَعْ مَا شِئْتَ",
        text: "Certes, parmi ce que les gens ont retenu des premières prophéties : 'Si tu n'as pas de pudeur, fais ce que tu veux'.",
        source: "Hadith 20 - Bukhari"
      },
      {
        arabic: "قُلْ: آمَنْتُ بِاللَّهِ ثُمَّ اسْتَقِمْ",
        text: "Dis : 'J'ai cru en Allah', puis tiens-toi droit (sur le chemin de la rectitude).",
        source: "Hadith 21 - Muslim"
      },
      {
        arabic: "أَرَأَيْتَ إِذَا صَلَّيْتُ الْمَكْتُوبَاتِ، وَصُمْتُ رَمَضَانَ، وَأَحْلَلْتُ الْحَلَالَ، وَحَرَّمْتُ الْحَرَامَ... أَأَدْخُلُ الْجَنَّةَ؟ قَالَ: نَعَمْ",
        text: "Vois-tu si je prie les prières obligatoires, jeûne le Ramadan, rends licite le licite et illicite l'illicite, et que je n'ajoute rien à cela, entrerai-je au Paradis ? Il dit : 'Oui'.",
        source: "Hadith 22 - Muslim"
      },
      {
        arabic: "الطُّهُورُ شَطْرُ الْإِيمَانِ، وَالْحَمْدُ لِلَّهِ تَمْلَأُ الْمِيزَانَ",
        text: "La purification est la moitié de la foi. 'Al-Hamdulillah' remplit la balance. 'SubhanAllah wal-Hamdulillah' remplissent ce qu'il y a entre le ciel et la terre.",
        source: "Hadith 23 - Muslim"
      },
      {
        arabic: "يَا عِبَادِي إِنِّي حَرَّمْتُ الظُّلْمَ عَلَى نَفْسِي وَجَعَلْتُهُ بَيْنَكُمْ مُحَرَّمًا، فَلَا تَظَالَمُوا",
        text: "Ô Mes serviteurs, Je Me suis interdit l'injustice à Moi-même et Je l'ai rendue interdite entre vous, alors ne vous opprimez pas les uns les autres.",
        source: "Hadith 24 - Muslim (Hadith Qudsi)"
      },
      {
        arabic: "كُلُّ سُلَامَى مِنَ النَّاسِ عَلَيْهِ صَدَقَةٌ",
        text: "Pour chaque articulation des gens, il y a une aumône (à faire) chaque jour où le soleil se lève. Être équitable entre deux personnes est une aumône...",
        source: "Hadith 25 - Bukhari & Muslim"
      },
      {
        arabic: "كُلُّ تَسْبِيحَةٍ صَدَقَةٌ، وَكُلُّ تَحْمِيدَةٍ صَدَقَةٌ",
        text: "Chaque Tasbih est une aumône, chaque Tahmid est une aumône, chaque Tahlil est une aumône, ordonner le bien est une aumône...",
        source: "Hadith 26 - Muslim"
      },
      {
        arabic: "الْبِرُّ حُسْنُ الْخُلُقِ، وَالْإِثْمُ مَا حَاكَ فِي صَدْرِكَ وَكَرِهْتَ أَنْ يَطَّلِعَ عَلَيْهِ النَّاسُ",
        text: "La piété, c'est le bon comportement. Et le péché, c'est ce qui se trame dans ta poitrine et que tu détesterais que les gens découvrent.",
        source: "Hadith 27 - Muslim"
      },
      {
        arabic: "عَلَيْكُمْ بِسُنَّتِي وَسُنَّةِ الْخُلَفَاءِ الرَّاشِدِينَ الْمَهْدِيِّينَ",
        text: "Attachez-vous à ma Sunnah et à la Sunnah des Califes bien guidés après moi. Mordez-y à pleines dents.",
        source: "Hadith 28 - Abu Dawud & Tirmidhi"
      },
      {
        arabic: "أَلَا أُخْبِرُكَ بِرَأْسِ الْأَمْرِ كُلِّهِ وَعَمُودِهِ وَذِرْوَةِ سَنَامِهِ؟",
        text: "Ne t'informerais-je pas de la tête de l'affaire, de son pilier et de son sommet ? La tête de l'affaire est l'Islam, son pilier est la prière, et son sommet est le Jihad.",
        source: "Hadith 29 - Tirmidhi"
      },
      {
        arabic: "إِنَّ اللَّهَ تَعَالَى فَرَضَ فَرَائِضَ فَلَا تُضَيِّعُوهَا، وَحَدَّ حُدُودًا فَلَا تَعْتَدُوهَا",
        text: "Allah a prescrit des obligations, ne les négligez pas. Il a fixé des limites, ne les transgressez pas. Il a tu certaines choses par miséricorde, ne cherchez pas après elles.",
        source: "Hadith 30 - Daraqutni"
      },
      {
        arabic: "ازْهَدْ فِي الدُّنْيَا يُحِبَّكَ اللَّهُ، وَازْهَدْ فِيمَا عِنْدَ النَّاسِ يُحِبَّكَ النَّاسُ",
        text: "Renonce à ce bas-monde, Allah t'aimera. Et renonce à ce que les gens possèdent, les gens t'aimeront.",
        source: "Hadith 31 - Ibn Majah"
      },
      {
        arabic: "لَا ضَرَرَ وَلَا ضِرَارَ",
        text: "Pas de nuisance (à autrui) et pas de nuisance réciproque.",
        source: "Hadith 32 - Ibn Majah"
      },
      {
        arabic: "الْبَيِّنَةُ عَلَى الْمُدَّعِي، وَالْيَمِينُ عَلَى مَنْ أَنْكَرَ",
        text: "La preuve incombe au demandeur, et le serment incombe à celui qui nie.",
        source: "Hadith 33 - Bayhaqi"
      },
      {
        arabic: "مَنْ رَأَى مِنْكُمْ مُنْكَرًا فَلْيُغَيِّرْهُ بِيَدِهِ...",
        text: "Que celui d'entre vous qui voit un mal le change de sa main ; s'il ne peut pas, alors de sa langue ; s'il ne peut pas, alors de son cœur, et c'est là le plus faible de la foi.",
        source: "Hadith 34 - Muslim"
      },
      {
        arabic: "لَا تَحَاسَدُوا، وَلَا تَنَاجَشُوا، وَلَا تَبَاغَضُوا... وَكُونُوا عِبَادَ اللَّهِ إِخْوَانًا",
        text: "Ne vous jalousez pas, ne surenchérissez pas, ne vous haïssez pas... et soyez, serviteurs d'Allah, des frères. Le musulman est le frère du musulman.",
        source: "Hadith 35 - Muslim"
      },
      {
        arabic: "مَنْ نَفَّسَ عَنْ مُؤْمِنٍ كُرْبَةً مِنْ كُرَبِ الدُّنْيَا، نَفَّسَ اللَّهُ عَنْهُ كُرْبَةً مِنْ كُرَبِ يَوْمِ الْقِيَامَةِ",
        text: "Celui qui soulage un croyant d'une détresse de ce monde, Allah le soulagera d'une détresse du Jour de la Résurrection. Et Allah aide le serviteur tant que le serviteur aide son frère.",
        source: "Hadith 36 - Muslim"
      },
      {
        arabic: "إِنَّ اللَّهَ كَتَبَ الْحَسَنَاتِ وَالسَّيِّئَاتِ ثُمَّ بَيَّنَ ذَلِكَ...",
        text: "Allah a écrit les bonnes et les mauvaises actions... Celui qui a l'intention de faire une bonne action mais ne la fait pas, Allah la lui inscrit comme une bonne action complète.",
        source: "Hadith 37 - Bukhari & Muslim"
      },
      {
        arabic: "مَنْ عَادَى لِي وَلِيًّا فَقَدْ آذَنْتُهُ بِالْحَرْبِ",
        text: "Celui qui montre de l'hostilité envers un de Mes alliés (Wali), Je lui déclare la guerre. Mon serviteur ne se rapproche pas de Moi par une chose que J'aime plus que ce que Je lui ai imposé...",
        source: "Hadith 38 - Bukhari"
      },
      {
        arabic: "إِنَّ اللَّهَ تَجَاوَزَ لِي عَنْ أُمَّتِي الْخَطَأَ وَالنِّسْيَانَ وَمَا اسْتُكْرِهُوا عَلَيْهِ",
        text: "Certes, Allah a pardonné à ma communauté l'erreur, l'oubli et ce à quoi ils ont été contraints.",
        source: "Hadith 39 - Ibn Majah"
      },
      {
        arabic: "كُنْ فِي الدُّنْيَا كَأَنَّكَ غَرِيبٌ أَوْ عَابِرُ سَبِيلٍ",
        text: "Sois dans ce bas-monde comme un étranger ou un voyageur de passage.",
        source: "Hadith 40 - Bukhari"
      },
      {
        arabic: "لَا يُؤْمِنُ أَحَدُكُمْ حَتَّى يَكُونَ هَوَاهُ تَبَعًا لِمَا جِئْتُ بِهِ",
        text: "Aucun de vous ne croit vraiment tant que ses désirs ne suivent pas ce avec quoi je suis venu.",
        source: "Hadith 41 - Nawawi (Hasan)"
      },
      {
        arabic: "يَا ابْنَ آدَمَ، إِنَّكَ مَا دَعَوْتَنِي وَرَجَوْتَنِي غَفَرْتُ لَكَ عَلَى مَا كَانَ فِيكَ وَلَا أُبَالِي",
        text: "Ô fils d'Adam, tant que tu M'invoques et que tu espères en Moi, Je te pardonne ce qu'il y a en toi et Je ne M'en soucie pas. Ô fils d'Adam, si tes péchés atteignaient le ciel puis que tu Me demandais pardon, Je te pardonnerais.",
        source: "Hadith 42 - Tirmidhi"
      }
    ]
  },
  {
    id: 'foi_adoration',
    title: "Foi, Invocation & Prière",
    icon: Moon,
    description: "Le Thikr, la Prière, l'Istikhara, le Tawakkul et le Coran",
    hadiths: [
      { arabic: "إِنَّمَا الأَعْمَالُ بِالنِّيَّاتِ", text: "Les actes ne valent que par les intentions.", source: "Sahih Bukhari" },
      { arabic: "الدُّعَاءُ مُخُّ الْعِبَادَةِ", text: "L'invocation est l'essence de l'adoration.", source: "Tirmidhi" },
      { arabic: "أَقْرَبُ مَا يَكُونُ الْعَبْدُ مِنْ رَبِّهِ وَهُوَ سَاجِدٌ", text: "Le serviteur est le plus proche de son Seigneur lorsqu'il est prosterné.", source: "Muslim" },
      { arabic: "مَنْ صَلَّى عَلَيَّ وَاحِدَةً صَلَّى اللَّهُ عَلَيْهِ عَشْرًا", text: "Celui qui prie sur moi une fois, Allah prie sur lui dix fois.", source: "Muslim" },
      { arabic: "الطُّهُورُ شَطْرُ الإِيمَانِ", text: "La pureté est la moitié de la foi.", source: "Muslim" },
      { arabic: "أَحَبُّ الْأَعْمَالِ إِلَى اللَّهِ أَدْوَمُهَا وَإِنْ قَلَّ", text: "Les actes les plus aimés d'Allah sont ceux qui sont les plus constants, même s'ils sont peu nombreux.", source: "Bukhari & Muslim" },
      { arabic: "الْعَهْدُ الَّذِي بَيْنَنَا وَبَيْنَهُمُ الصَّلَاةُ", text: "Le pacte entre nous et eux est la prière.", source: "Tirmidhi" },
      { arabic: "مَنْ قَامَ رَمَضَانَ إِيمَانًا وَاحْتِسَابًا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ", text: "Celui qui veille Ramadan avec foi et espérance, ses péchés passés lui sont pardonnés.", source: "Bukhari & Muslim" },
      { arabic: "لَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِ كَنْزٌ مِنْ كُنُوزِ الْجَنَّةِ", text: "La Hawla wa la Quwwata illa Billah est un trésor du Paradis.", source: "Bukhari & Muslim" },
      { arabic: "مَنْ قَرَأَ قُلْ هُوَ اللَّهُ أَحَدٌ عَشْرَ مَرَّاتٍ بَنَى اللَّهُ لَهُ بَيْتًا فِي الْجَنَّةِ", text: "Celui qui récite 'Qul Huwa Allahu Ahad' dix fois, Allah lui construit une maison au Paradis.", source: "Ahmad" },
      { arabic: "أَفْضَلُ الذِّكْرِ لَا إِلَهَ إِلَّا اللَّهُ", text: "Le meilleur rappel est La ilaha illa Allah.", source: "Tirmidhi" },
      { arabic: "يَا مُقَلِّبَ الْقُلُوبِ ثَبِّتْ قَلْبِي عَلَى دِينِكَ", text: "Ô Toi qui retournes les cœurs, affermis mon cœur sur Ta religion.", source: "Tirmidhi" },
      { arabic: "صَلَاةُ الْجَمَاعَةِ تَفْضُلُ صَلَاةَ الْفَذِّ بِسَبْعٍ وَعِشْرِينَ دَرَجَةً", text: "La prière en groupe dépasse la prière individuelle de vingt-sept degrés.", source: "Bukhari & Muslim" },
      { arabic: "مَنْ بَنَى مَسْجِدًا لِلَّهِ بَنَى اللَّهُ لَهُ فِي الْجَنَّةِ مِثْلَهُ", text: "Celui qui construit une mosquée pour Allah, Allah lui construit l'équivalent au Paradis.", source: "Bukhari & Muslim" },
      { arabic: "الْمَاهِرُ بِالْقُرْآنِ مَعَ السَّفَرَةِ الْكِرَامِ الْبَرَرَةِ", text: "L'expert dans le Coran sera avec les anges nobles et pieux.", source: "Muslim" },
      { arabic: "اقْرَءُوا الْقُرْآنَ فَإِنَّهُ يَأْتِي يَوْمَ الْقِيَامَةِ شَفِيعًا لِأَصْحَابِهِ", text: "Lisez le Coran, car il viendra le Jour de la Résurrection comme intercesseur pour les siens.", source: "Muslim" },
      { arabic: "مَنْ صَامَ رَمَضَانَ ثُمَّ أَتْبَعَهُ سِتًّا مِنْ شَوَّالٍ كَانَ كَصِيَامِ الدَّهْرِ", text: "Celui qui jeûne le Ramadan puis le fait suivre de six jours de Shawwal, c'est comme s'il avait jeûné toute l'année.", source: "Muslim" },
      { arabic: "عُمْرَةٌ فِي رَمَضَانَ تَعْدِلُ حَجَّةً", text: "Une Omra pendant le Ramadan équivaut à un Hajj.", source: "Bukhari & Muslim" },
      { arabic: "خَيْرُ الدُّعَاءِ دُعَاءُ يَوْمِ عَرَفَةَ", text: "La meilleure invocation est celle du jour de Arafat.", source: "Tirmidhi" },
      { arabic: "مَنْ يُرِدِ اللَّهُ بِهِ خَيْرًا يُفَقِّهْهُ فِي الدِّينِ", text: "Celui à qui Allah veut du bien, Il lui accorde la compréhension de la religion.", source: "Bukhari" },
      { arabic: "إِنَّ اللَّهَ يُحِبُّ الْوِتْرَ فَأَوْتِرُوا", text: "Certes Allah est impair (Unique) et Il aime l'impair, alors priez le Witr.", source: "Abu Dawud" },
      { arabic: "رَكْعَتَا الْفَجْرِ خَيْرٌ مِنَ الدُّنْيَا وَمَا فِيهَا", text: "Les deux unités de prière du Fajr (Sunnah) sont meilleures que ce bas-monde et ce qu'il contient.", source: "Muslim" },
      { arabic: "مَنْ حَافَظَ عَلَى أَرْبَعِ رَكَعَاتٍ قَبْلَ الظُّهْرِ وَأَرْبَعٍ بَعْدَهَا حَرَّمَهُ اللَّهُ عَلَى النَّارِ", text: "Celui qui est assidu à quatre unités avant le Dhuhr et quatre après, Allah l'interdit au Feu.", source: "Tirmidhi" },
      { arabic: "لَوْلَا أَنْ أَشُقَّ عَلَى أُمَّتِي لَأَمَرْتُهُمْ بِالسِّوَاكِ عِنْدَ كُلِّ صَلَاةٍ", text: "Si je ne craignais de surcharger ma communauté, je leur aurais ordonné le Siwak à chaque prière.", source: "Bukhari" },
      { arabic: "مَنْ غَدَا إِلَى الْمَسْجِدِ وَرَاحَ أَعَدَّ اللَّهُ لَهُ نُزُلَهُ مِنَ الْجَنَّةِ كُلَّمَا غَدَا أَوْ رَاحَ", text: "Celui qui va à la mosquée matin et soir, Allah lui prépare une demeure au Paradis à chaque aller-retour.", source: "Bukhari & Muslim" },
      { arabic: "الْبُخْلُ مَنْ ذُكِرْتُ عِنْدَهُ فَلَمْ يُصَلِّ عَلَيَّ", text: "L'avare est celui auprès de qui je suis mentionné et qui ne prie pas sur moi.", source: "Tirmidhi" },
      { arabic: "الدُّعَاءُ بَيْنَ الْأَذَانِ وَالْإِقَامَةِ لَا يُرَدُّ", text: "L'invocation entre l'Adhan et l'Iqama n'est pas rejetée.", source: "Tirmidhi" },
      { arabic: "مَنْ نَسِيَ وَهُوَ صَائِمٌ فَأَكَلَ أَوْ شَرِبَ فَلْيُتِمَّ صَوْمَهُ", text: "Celui qui oublie en jeûnant et mange ou boit, qu'il termine son jeûne.", source: "Bukhari & Muslim" },
      { arabic: "تَسَحَّرُوا فَإِنَّ فِي السَّحُورِ بَرَكَةً", text: "Prenez le Suhur, car il y a une bénédiction dans le Suhur.", source: "Bukhari & Muslim" },
      { arabic: "الصَّوْمُ جُنَّةٌ", text: "Le jeûne est un bouclier.", source: "Bukhari & Muslim" },
      { arabic: "لِلصَّائِمِ فَرْحَتَانِ: فَرْحَةٌ عِنْدَ فِطْرِهِ وَفَرْحَةٌ عِنْدَ لِقَاءِ رَبِّهِ", text: "Le jeûneur a deux joies : une quand il rompt son jeûne et une quand il rencontre son Seigneur.", source: "Muslim" },
      { arabic: "مَنْ قَامَ لَيْلَةَ الْقَدْرِ إِيمَانًا وَاحْتِسَابًا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ", text: "Celui qui prie la nuit du Destin avec foi et espérance, ses péchés passés sont pardonnés.", source: "Bukhari" },
      { arabic: "أَحَبُّ الْكَلَامِ إِلَى اللَّهِ أَرْبَعٌ: سُبْحَانَ اللَّهِ، وَالْحَمْدُ لِلَّهِ، وَلَا إِلَهَ إِلَّا اللَّهُ، وَاللَّهُ أَكْبَرُ", text: "Les paroles les plus aimées d'Allah sont quatre : Gloire à Allah, Louange à Allah, Il n'y a de dieu qu'Allah, Allah est le Plus Grand.", source: "Muslim" },
      { arabic: "مَنْ قَالَ سُبْحَانَ اللَّهِ الْعَظِيمِ وَبِحَمْدِهِ غُرِسَتْ لَهُ نَخْلَةٌ فِي الْجَنَّةِ", text: "Celui qui dit 'SubhanAllah Al-Azim wa bihamdihi', un palmier lui est planté au Paradis.", source: "Tirmidhi" },
      { arabic: "إِنَّ لِلَّهِ تِسْعَةً وَتِسْعِينَ اسْمًا مَنْ أَحْصَاهَا دَخَلَ الْجَنَّةَ", text: "Allah a 99 noms, celui qui les retient (et agit selon eux) entrera au Paradis.", source: "Bukhari & Muslim" },
      { arabic: "اللَّهُمَّ أَعِنِّي عَلَى ذِكْرِكَ وَشُكْرِكَ وَحُسْنِ عِبَادَتِكَ", text: "Ô Allah, aide-moi à T'évoquer, à Te remercier et à T'adorer de la meilleure façon.", source: "Abu Dawud" },
      { arabic: "مَنْ لَزِمَ الِاسْتِغْفَارَ جَعَلَ اللَّهُ لَهُ مِنْ كُلِّ ضِيقٍ مَخْرَجًا", text: "Celui qui s'attache à la demande de pardon, Allah lui accorde une issue à toute difficulté.", source: "Abu Dawud" },
      { arabic: "سَيِّدُ الِاسْتِغْفَارِ أَنْ تَقُولَ اللَّهُمَّ أَنْتَ رَبِّي لَا إِلَهَ إِلَّا أَنْتَ", text: "La formule maîtresse du pardon est de dire : Ô Allah Tu es mon Seigneur...", source: "Bukhari" },
      { arabic: "الْبَرُّ لاَ يَبْلَى، وَالذَّنْبُ لاَ يُنْسَى، وَالدَّيَّانُ لاَ يَمُوتُ", text: "Le bien ne s'use pas, le péché ne s'oublie pas, et le Juge ne meurt pas.", source: "Bayhaqi" },
      { arabic: "خَيْرُ يَوْمٍ طَلَعَتْ عَلَيْهِ الشَّمْسُ يَوْمُ الْجُمُعَةِ", text: "Le meilleur jour où le soleil s'est levé est le vendredi.", source: "Muslim" },
      { arabic: "مَنْ غَسَّلَ يَوْمَ الْجُمُعَةِ وَاغْتَسَلَ... غُفِرَ لَهُ مَا بَيْنَهُ وَبَيْنَ الْجُمُعَةِ الْأُخْرَى", text: "Celui qui fait le lavage rituel le vendredi... ses péchés entre ce vendredi et le suivant sont pardonnés.", source: "Bukhari" },
      { arabic: "إِنَّمَا الأَعْمَالُ بِالْخَوَاتِيمِ", text: "Les actes ne valent que par leur fin.", source: "Bukhari" }
    ]
  },
  {
    id: 'savoir',
    title: "Science & Raison",
    icon: GraduationCap,
    description: "Le mérite du savoir, des savants et de la réflexion",
    hadiths: [
      { arabic: "طَلَبُ الْعِلْمِ فَرِيضَةٌ عَلَى كُلِّ مُسْلِمٍ", text: "La recherche de la science est une obligation pour tout musulman.", source: "Ibn Majah" },
      { arabic: "مَنْ سَلَكَ طَرِيقًا يَلْتَمِسُ فِيهِ عِلْمًا سَهَّلَ اللَّهُ لَهُ بِهِ طَرِيقًا إِلَى الْجَنَّةِ", text: "Celui qui emprunte un chemin vers la science, Allah lui facilite un chemin vers le Paradis.", source: "Muslim" },
      { arabic: "الْعُلَمَاءُ وَرَثَةُ الأَنْبِيَاءِ", text: "Les savants sont les héritiers des prophètes.", source: "Abu Dawud" },
      { arabic: "بَلِّغُوا عَنِّي وَلَوْ آيَةً", text: "Transmettez de moi, ne serait-ce qu'un verset.", source: "Bukhari" },
      { arabic: "إِنَّ الْمَلَائِكَةَ لَتَضَعُ أَجْنِحَتَهَا رِضًا لِطَالِبِ الْعِلْمِ", text: "Les anges abaissent leurs ailes pour l'étudiant en science par satisfaction.", source: "Tirmidhi" },
      { arabic: "فَضْلُ الْعَالِمِ عَلَى الْعَابِدِ كَفَضْلِ الْقَمَرِ عَلَى سَائِرِ الْكَوَاكِبِ", text: "Le mérite du savant sur l'adorateur est comme celui de la lune sur les étoiles.", source: "Tirmidhi" },
      { arabic: "مَنْ يُرِدِ اللَّهُ بِهِ خَيْرًا يُفَقِّهْهُ فِي الدِّينِ", text: "Celui à qui Allah veut du bien, Il lui accorde la compréhension de la religion.", source: "Bukhari" },
      { arabic: "إِذَا مَاتَ الإِنْسَانُ انْقَطَعَ عَنْهُ عَمَلُهُ إِلاَّ مِنْ ثَلاَثَةٍ... أَوْ عِلْمٍ يُنْتَفَعُ بِهِ", text: "Quand l'homme meurt, ses actes cessent sauf trois... dont une science utile.", source: "Muslim" },
      { arabic: "الدُّنْيَا مَلْعُونَةٌ... إِلاَّ ذِكْرَ اللَّهِ... وَعَالِمًا أَوْ مُتَعَلِّمًا", text: "Ce monde est maudit... sauf le rappel d'Allah... un savant ou un étudiant.", source: "Tirmidhi" },
      { arabic: "إِنَّمَا الْعِلْمُ بِالتَّعَلُّمِ", text: "La science ne s'acquiert que par l'apprentissage.", source: "Tabarani" },
      { arabic: "اللَّهُمَّ إِنِّي أَسْأَلُكَ عِلْمًا نَافِعًا", text: "Ô Allah, je Te demande une science utile.", source: "Ibn Majah" },
      { arabic: "خَيْرُكُمْ مَنْ تَعَلَّمَ الْقُرْآنَ وَعَلَّمَهُ", text: "Le meilleur d'entre vous est celui qui apprend le Coran et l'enseigne.", source: "Bukhari" },
      { arabic: "مَنْ دَلَّ عَلَى خَيْرٍ فَلَهُ مِثْلُ أَجْرِ فَاعِلِهِ", text: "Celui qui montre le bien a la même récompense que celui qui le fait.", source: "Muslim" },
      { arabic: "نَضَّرَ اللَّهُ امْرَأً سَمِعَ مِنَّا شَيْئًا فَبَلَّغَهُ كَمَا سَمِعَهُ", text: "Qu'Allah illumine le visage de celui qui entend de nous quelque chose et le transmet tel qu'il l'a entendu.", source: "Tirmidhi" },
      { arabic: "الْكَلِمَةُ الْحِكْمَةُ ضَالَّةُ الْمُؤْمِنِ", text: "La sagesse est l'objet perdu du croyant.", source: "Tirmidhi" },
      { arabic: "مَنْ كَذَبَ عَلَيَّ مُتَعَمِّدًا فَلْيَتَبَوَّأْ مَقْعَدَهُ مِنَ النَّارِ", text: "Celui qui ment sur moi volontairement, qu'il prépare sa place en Enfer.", source: "Bukhari" },
      { arabic: "إِنَّ مِنْ أَشْرَاطِ السَّاعَةِ أَنْ يُرْفَعَ الْعِلْمُ وَيَثْبُتَ الْجَهْلُ", text: "Parmi les signes de l'Heure : la science sera retirée et l'ignorance s'installera.", source: "Bukhari" },
      { arabic: "إِنَّ اللَّهَ لاَ يَقْبِضُ الْعِلْمَ انْتِزَاعًا... وَلَكِنْ يَقْبِضُ الْعِلْمَ بِقَبْضِ الْعُلَمَاءِ", text: "Allah ne retire pas la science brutalement, mais en reprenant les savants.", source: "Bukhari" },
      { arabic: "أَلاَ سَأَلُوا إِذْ لَمْ يَعْلَمُوا فَإِنَّمَا شِفَاءُ الْعِيِّ السُّؤَالُ", text: "Pourquoi n'ont-ils pas demandé s'ils ne savaient pas ? Le remède de l'ignorance est la question.", source: "Abu Dawud" },
      { arabic: "مَنْ سُئِلَ عَنْ عِلْمٍ فَكَتَمَهُ أُلْجِمَ يَوْمَ الْقِيَامَةِ بِلِجَامٍ مِنْ نَارٍ", text: "Celui qui cache une science sera bridé par du feu le Jour de la Résurrection.", source: "Tirmidhi" },
      { arabic: "يَحْمِلُ هَذَا الْعِلْمَ مِنْ كُلِّ خَلَفٍ عُدُولُهُ", text: "Porteront cette science à chaque génération ses gens intègres.", source: "Bayhaqi" },
      { arabic: "قَلِيلُ الْعِلْمِ خَيْرٌ مِنْ كَثِيرِ الْعِبَادَةِ", text: "Un peu de science vaut mieux que beaucoup d'adoration.", source: "Tabarani" },
      { arabic: "اغْدُ عَالِمًا أَوْ مُتَعَلِّمًا أَوْ مُسْتَمِعًا أَوْ مُحِبًّا وَلَا تَكُنِ الْخَامِسَةَ فَتَهْلِك", text: "Sois savant, étudiant, auditeur ou aimant la science, mais ne sois pas le cinquième (ignorant) sinon tu périras.", source: "Tabarani" },
      { arabic: "إِنَّ الْعُلَمَاءَ هُمْ أُمَنَاءُ الرُّسُلِ", text: "Les savants sont les dépositaires des messagers.", source: "Musnad" },
      { arabic: "آفَةُ الْعِلْمِ النِّسْيَانُ", text: "Le fléau de la science est l'oubli.", source: "Darimi" },
      { arabic: "زَكَاةُ الْعِلْمِ تَعْلِيمُهُ", text: "La Zakat de la science est de l'enseigner.", source: "Ibn Asakir" },
      { arabic: "مَنْ خَرَجَ فِي طَلَبِ الْعِلْمِ فَهُوَ فِي سَبِيلِ اللَّهِ حَتَّى يَرْجِعَ", text: "Celui qui sort pour la science est dans le sentier d'Allah jusqu'à ce qu'il revienne.", source: "Tirmidhi" },
      { arabic: "لَأَنْ يَهْدِيَ اللَّهُ بِكَ رَجُلًا وَاحِدًا خَيْرٌ لَكَ مِنْ حُمْرِ النَّعَمِ", text: "Qu'Allah guide par toi un seul homme est meilleur pour toi que les chameaux rouges (biens précieux).", source: "Bukhari" },
      { arabic: "مَنْ عَمِلَ بِمَا عَلِمَ وَرَّثَهُ اللَّهُ عِلْمَ مَا لَمْ يَعْلَمْ", text: "Celui qui agit selon ce qu'il sait, Allah lui donne la science de ce qu'il ne savait pas.", source: "Hilyat al-Awliya" },
      { arabic: "رُبَّ حَامِلِ فِقْهٍ إِلَى مَنْ هُوَ أَفْقَهُ مِنْهُ", text: "Il se peut que celui qui porte la science la transmette à plus savant que lui.", source: "Tirmidhi" },
