import React from 'react';
import { Home, MapPin, MessageCircle, BookOpen, ScrollText, Library } from 'lucide-react';

interface NavigationProps {
  activeTab: string;
  setActiveTab: (tab: string) => void;
  language?: string;
}

const TRANSLATIONS = {
  en: { home: 'Home', quran: 'Quran', mosques: 'Mosques', chat: 'Ask AI', hadith: 'Hadith' },
  fr: { home: 'Accueil', quran: 'Coran', mosques: 'Mosquées', chat: 'IA', hadith: 'Hadith' }
};

const Navigation: React.FC<NavigationProps> = ({ activeTab, setActiveTab, language = 'en' }) => {
  const t = TRANSLATIONS[language as keyof typeof TRANSLATIONS] || TRANSLATIONS.en;

  const navItems = [
    { id: 'home', icon: Home, label: t.home },
    { id: 'quran', icon: BookOpen, label: t.quran },
    { id: 'hadith', icon: Library, label: t.hadith },
    { id: 'mosques', icon: MapPin, label: t.mosques },
    { id: 'chat', icon: MessageCircle, label: t.chat },
  ];

  return (
    <nav className="fixed bottom-0 left-0 right-0 bg-white/95 dark:bg-slate-950/95 backdrop-blur-lg border-t border-slate-200 dark:border-slate-800 pb-safe pt-2 px-2 shadow-[0_-4px_10px_rgba(0,0,0,0.03)] z-50 md:hidden transition-all duration-300">
      <div className="flex justify-between items-center max-w-sm mx-auto">
        {navItems.map((item) => {
          const Icon = item.icon;
          const isActive = activeTab === item.id;
          return (
            <button
              key={item.id}
              onClick={() => setActiveTab(item.id)}
              className={`relative flex flex-col items-center gap-1 p-2 rounded-2xl transition-all duration-300 w-12 sm:w-14 group ${
                isActive 
                  ? 'text-emerald-600 dark:text-emerald-400' 
                  : 'text-slate-400 dark:text-slate-500 hover:text-slate-600 dark:hover:text-slate-300'
              }`}
            >
              {/* Active Indicator Background */}
              {isActive && (
                <div className="absolute inset-0 bg-emerald-50 dark:bg-emerald-900/20 rounded-2xl -z-10 animate-fade-in scale-100 opacity-100"></div>
              )}

              <div className={`relative p-1 transition-transform duration-300 ${isActive ? '-translate-y-0.5' : ''}`}>
                 <Icon size={24} strokeWidth={isActive ? 2.5 : 2} className="transition-all" />
              </div>

              <span className={`text-[10px] font-medium transition-all duration-300 ${isActive ? 'font-bold scale-105' : 'font-medium'} truncate w-full text-center`}>
                {item.label}
              </span>

              {/* Bottom Dot for Active State */}
              {isActive && (
                 <span className="absolute bottom-1 w-1 h-1 bg-current rounded-full"></span>
              )}
            </button>
          );
        })}
      </div>
    </nav>
  );
};

export default Navigation;

