    continue: "Continuer la lecture",
    lastRead: "Dernière lecture",
    results: "Résultats de recherche",
    ayah: "Verset",
    verses: "Versets",
    selectReciter: "Choisir un Récitateur",
    playing: "Lecture en cours"
  }
};

const QuranReader: React.FC<QuranReaderProps> = ({ language = 'en' }) => {
  const [surahs, setSurahs] = useState<Surah[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [searchTerm, setSearchTerm] = useState('');
  const [activeSurah, setActiveSurah] = useState<Surah | null>(null);
  const [ayahs, setAyahs] = useState<{arabic: string, translation: string, number: number}[]>([]);
  const [loadingSurah, setLoadingSurah] = useState(false);
  const [lastRead, setLastRead] = useState<LastRead | null>(null);
  const [progress, setProgress] = useState<Record<number, number>>({});

  // Audio State
  const [reciters, setReciters] = useState<Reciter[]>(POPULAR_RECITERS);
  const [activeReciter, setActiveReciter] = useState<Reciter>({ 
      identifier: 'ar.alafasy', 
      name: 'Mishary Rashid Alafasy', 
      englishName: 'Alafasy', 
      format: 'audio',
      language: 'ar'
  });
  const [showReciterList, setShowReciterList] = useState(false);
  const [audioUrls, setAudioUrls] = useState<string[]>([]);
  const [currentAudioIndex, setCurrentAudioIndex] = useState(-1);
  const [isPlaying, setIsPlaying] = useState(false);
  const [loadingAudio, setLoadingAudio] = useState(false);
  const [playbackSpeed, setPlaybackSpeed] = useState(1);
  const [repeatMode, setRepeatMode] = useState<'none' | 'all' | 'one'>('none');

  const topRef = useRef<HTMLDivElement>(null);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  const t = TRANSLATIONS[language as keyof typeof TRANSLATIONS] || TRANSLATIONS.en;

  // Fetch Data & Initialize
  useEffect(() => {
    const fetchData = async () => {
      try {
        // Load Persisted Data
        const savedProgress = localStorage.getItem('quran_last_read');
        if (savedProgress) setLastRead(JSON.parse(savedProgress));

        const savedReadingProgress = localStorage.getItem('reading_progress');
        if (savedReadingProgress) setProgress(JSON.parse(savedReadingProgress));

        const cachedReciters = localStorage.getItem('quran_reciters');
        if (cachedReciters) {
            setReciters(JSON.parse(cachedReciters));
        } else {
            // Fetch more reciters from API
            fetch('https://api.alquran.cloud/v1/edition?format=audio&language=ar&type=versebyverse')
                .then(res => res.json())
                .then(data => {
                    if (data.code === 200) {
                        // Merge popular reciters with API results (popular first, remove duplicates)
                        const apiReciters = data.data;
                        const popularIds = new Set(POPULAR_RECITERS.map(r => r.identifier));
                        const others = apiReciters.filter((r: Reciter) => !popularIds.has(r.identifier));
                        const allReciters = [...POPULAR_RECITERS, ...others];

                        setReciters(allReciters);
                        localStorage.setItem('quran_reciters', JSON.stringify(allReciters));
                    }
                })
                .catch(console.error);
        }

        const cached = localStorage.getItem('quran_surahs');
        if (cached) {
            setSurahs(JSON.parse(cached));
            setLoading(false);
            return;
        }

        const res = await fetch('https://api.alquran.cloud/v1/surah');
        const data = await res.json();
        if (data.code === 200) {
          setSurahs(data.data);
          localStorage.setItem('quran_surahs', JSON.stringify(data.data));
        } else {
          setError('Failed to load Surahs');
        }
      } catch (err) {
        setError('Network error. Please check connection.');
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, []);

  // Save Progress Effect
  useEffect(() => {
    localStorage.setItem('reading_progress', JSON.stringify(progress));
  }, [progress]);

  // Intersection Observer for Progress Tracking
  useEffect(() => {
    if (!activeSurah || loadingSurah || ayahs.length === 0) return;

    const observer = new IntersectionObserver((entries) => {
      entries.forEach(entry => {
        if (entry.isIntersecting) {
          const ayahNum = parseInt(entry.target.getAttribute('data-ayah-number') || '0');
          if (ayahNum > 0) {
             setProgress(prev => {
                const currentMax = prev[activeSurah.number] || 0;
                // Only update if we've read further
                if (ayahNum > currentMax) {
                   return { ...prev, [activeSurah.number]: ayahNum };
                }
                return prev;
             });
          }
        }
      });
    }, { threshold: 0.6 }); // Verse must be 60% visible to count as "reading"

    // Observe after a slight delay to ensure render
    setTimeout(() => {
        document.querySelectorAll('.ayah-item').forEach(el => observer.observe(el));
    }, 500);

    return () => observer.disconnect();
  }, [activeSurah, loadingSurah, ayahs]);

  // Fetch Specific Surah
  const selectSurah = async (surah: Surah) => {
    setActiveSurah(surah);
    setLoadingSurah(true);
    setAyahs([]);
    resetAudio();

    const progressRecord: LastRead = {
        number: surah.number,
        name: surah.name,
        englishName: surah.englishName,
        timestamp: Date.now()
    };
    setLastRead(progressRecord);
    localStorage.setItem('quran_last_read', JSON.stringify(progressRecord));

    // Choose translation edition based on language
    const translationEdition = language === 'fr' ? 'fr.hamidullah' : 'en.sahih';

    try {
       const res = await fetch(`https://api.alquran.cloud/v1/surah/${surah.number}/editions/quran-uthmani,${translationEdition}`);
       const data = await res.json();

       if (data.code === 200 && data.data.length >= 2) {
           const arabicAyahs = data.data[0].ayahs;
           const translatedAyahs = data.data[1].ayahs;

           const combined = arabicAyahs.map((ayah: any, index: number) => ({
               number: ayah.numberInSurah,
               arabic: ayah.text,
               translation: translatedAyahs[index]?.text || ''
           }));

           setAyahs(combined);
           loadAudioForSurah(surah.number, activeReciter.identifier);
       }
    } catch (err) {
        console.error(err);
        setError('Failed to load verses.');
    } finally {
        setLoadingSurah(false);
        if(topRef.current) topRef.current.scrollTop = 0;
    }
  };

  const handleBack = () => {
    setActiveSurah(null);
    setAyahs([]);
    resetAudio();
  };

  // Audio Functions
  const resetAudio = () => {
      setIsPlaying(false);
      setCurrentAudioIndex(-1);
      setAudioUrls([]);
      if (audioRef.current) {
          audioRef.current.pause();
          audioRef.current.currentTime = 0;
      }
  };

  const togglePlay = async () => {
      if (loadingAudio) return;

      if (isPlaying) {
          audioRef.current?.pause();
          setIsPlaying(false);
      } else {
          if (audioUrls.length === 0 && activeSurah) {
              await loadAudioForSurah(activeSurah.number, activeReciter.identifier);
          }

          if (currentAudioIndex === -1) {
              // Start from the first unread verse if available, else 0
              const lastReadAyah = progress[activeSurah!.number] || 0;
              // If completed, start from 0, else start from last read
              setCurrentAudioIndex(lastReadAyah < (activeSurah?.numberOfAyahs || 1) ? lastReadAyah : 0); 
          } else {
              audioRef.current?.play();
          }
          setIsPlaying(true);
      }
  };

  const playAyah = (index: number) => {
      if (loadingAudio) return;

      if (currentAudioIndex === index) {
          if (isPlaying) {
              audioRef.current?.pause();
              setIsPlaying(false);
          } else {
              setIsPlaying(true);
          }
      } else {
          setCurrentAudioIndex(index);
          setIsPlaying(true);
      }
  };

  const cycleSpeed = () => {
    const speeds = [0.75, 1, 1.25, 1.5];
    const currentIndex = speeds.indexOf(playbackSpeed);
    const nextIndex = (currentIndex + 1) % speeds.length;
    setPlaybackSpeed(speeds[nextIndex]);
  };

  const toggleRepeat = () => {
    setRepeatMode(prev => {
        if (prev === 'none') return 'all';
        if (prev === 'all') return 'one';
        return 'none';
    });
  };

  const loadAudioForSurah = async (surahNumber: number, reciterId: string) => {
      setLoadingAudio(true);
      try {
          const res = await fetch(`https://api.alquran.cloud/v1/surah/${surahNumber}/${reciterId}`);
          const data = await res.json();
          if (data.code === 200) {
              const urls = data.data.ayahs.map((a: any) => a.audio);
              setAudioUrls(urls);
          }
      } catch (err) {
          console.error("Error loading audio", err);
      } finally {
          setLoadingAudio(false);
      }
  };

  const handleReciterChange = async (reciter: Reciter) => {
      setActiveReciter(reciter);
      setShowReciterList(false);
      if (activeSurah) {
          const wasPlaying = isPlaying;
          setIsPlaying(false);
          if(audioRef.current) audioRef.current.pause();
          await loadAudioForSurah(activeSurah.number, reciter.identifier);
          if (wasPlaying && currentAudioIndex !== -1) {
              setIsPlaying(true);
          }
      }
  };

  // Update playback rate when state changes
  useEffect(() => {
    if (audioRef.current) {
      audioRef.current.playbackRate = playbackSpeed;
    }
  }, [playbackSpeed]);

  useEffect(() => {
      const audio = audioRef.current;
      if (!audio) return;

      const playCurrentVerse = async () => {
          if (currentAudioIndex >= 0 && currentAudioIndex < audioUrls.length && isPlaying) {
              const url = audioUrls[currentAudioIndex];
              if (audio.src !== url) {
                  audio.src = url;
                  audio.playbackRate = playbackSpeed;
              }
              try {
                  await audio.play();
                  document.getElementById(`ayah-${currentAudioIndex + 1}`)?.scrollIntoView({ behavior: 'smooth', block: 'center' });
              } catch (e) {
                  console.error("Play failed", e);
                  setIsPlaying(false);
              }
          }
      };

      if (isPlaying) playCurrentVerse();

      const handleEnded = () => {
          if (repeatMode === 'one') {
              audio.currentTime = 0;
              audio.play();
          } else if (currentAudioIndex < audioUrls.length - 1) {
              setCurrentAudioIndex(prev => prev + 1);
          } else if (repeatMode === 'all') {
              setCurrentAudioIndex(0);
          } else {
              setIsPlaying(false);
              setCurrentAudioIndex(0);
          }
      };

      audio.addEventListener('ended', handleEnded);
      return () => audio.removeEventListener('ended', handleEnded);
  }, [currentAudioIndex, audioUrls, isPlaying, repeatMode]);


  const filteredSurahs = surahs.filter(s => 
    s.englishName.toLowerCase().includes(searchTerm.toLowerCase()) || 
    s.englishNameTranslation.toLowerCase().includes(searchTerm.toLowerCase()) ||
    s.number.toString().includes(searchTerm)
  );

  const continueReading = () => {
      if (lastRead) {
          const surah = surahs.find(s => s.number === lastRead.number);
          if (surah) selectSurah(surah);
      }
  };

  // Render List
  if (!activeSurah) {
     return (
        <div className="h-full flex flex-col animate-fade-in relative">
           <div className="px-6 pt-2 pb-4 bg-white dark:bg-slate-950 sticky top-0 z-10">
              <h1 className="text-2xl font-bold text-slate-800 dark:text-slate-100 mb-4">{t.title}</h1>
              <div className="relative">
                 <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                 <input 
                   type="text" 
                   placeholder={t.search} 
                   className="w-full bg-slate-100 dark:bg-slate-900 border-none rounded-xl py-3 pl-10 pr-4 text-slate-800 dark:text-slate-100 placeholder:text-slate-400 focus:ring-2 focus:ring-emerald-500/50 outline-none transition-all"
                   value={searchTerm}
                   onChange={(e) => setSearchTerm(e.target.value)}
                 />
              </div>
           </div>

           <div className="flex-1 overflow-y-auto px-6 pb-24">
              {loading ? (
                  <div className="flex justify-center pt-10"><Loader2 className="animate-spin text-emerald-600" size={32} /></div>
              ) : error ? (
                  <div className="flex flex-col items-center justify-center pt-10 text-center">
                    <AlertCircle className="text-red-500 mb-2" />
                    <p className="text-slate-600 dark:text-slate-400">{error}</p>
                    <button onClick={() => window.location.reload()} className="mt-4 text-emerald-600 font-medium">Retry</button>
                  </div>
              ) : (
                  <div className="space-y-3">
                      {/* Last Read Card */}
                      {lastRead && !searchTerm && (
                          <div className="mb-6 animate-fade-in">
                              <h2 className="text-xs font-bold text-slate-400 dark:text-slate-500 uppercase tracking-wider mb-3 px-1">{t.continue}</h2>
                              <button 
                                  onClick={continueReading}
                                  className="w-full bg-gradient-to-r from-emerald-600 to-teal-700 p-5 rounded-2xl text-white shadow-lg shadow-emerald-600/20 flex items-center justify-between group transform transition-all active:scale-[0.98]"
                              >
                                  <div className="flex items-center gap-4">
                                      <div className="w-12 h-12 bg-white/20 backdrop-blur-sm rounded-full flex items-center justify-center shadow-inner">
                                          <BookOpen size={22} className="text-white" />
                                      </div>
                                      <div className="text-left">
                                          <p className="text-emerald-100 text-xs font-medium mb-1 flex items-center gap-1">
                                            <Clock size={10} /> {t.lastRead}
                                          </p>
                                          <p className="font-bold text-xl">{lastRead.englishName}</p>
                                          {/* Mini Progress for Last Read */}
                                          {progress[lastRead.number] && (
                                              <div className="mt-1 flex items-center gap-2">
                                                  <div className="h-1 bg-black/20 rounded-full w-24 overflow-hidden">
                                                      <div 
                                                        className="h-full bg-emerald-200" 
                                                        style={{ width: `${(progress[lastRead.number] / (surahs.find(s=>s.number===lastRead.number)?.numberOfAyahs || 1)) * 100}%` }}
                                                      ></div>
                                                  </div>
                                                  <span className="text-[10px] text-emerald-100">
                                                      {t.ayah} {progress[lastRead.number]}
                                                  </span>
                                              </div>
                                          )}
                                      </div>
                                  </div>
                                  <div className="font-arabic text-3xl opacity-80 text-emerald-100">{lastRead.name.replace('سُورَةُ ', '')}</div>
                              </button>
                          </div>
                      )}

                      {/* Surah List */}
                      {searchTerm && <h2 className="text-xs font-bold text-slate-400 dark:text-slate-500 uppercase tracking-wider mb-3 px-1">{t.results}</h2>}

                      {filteredSurahs.map(surah => {
                          const surahProgress = progress[surah.number] || 0;
                          const percent = Math.round((surahProgress / surah.numberOfAyahs) * 100);

                          return (
                          <button 
                            key={surah.number}
                            onClick={() => selectSurah(surah)}
                            className="w-full bg-white dark:bg-slate-900 p-4 rounded-2xl border border-slate-100 dark:border-slate-800 hover:border-emerald-200 dark:hover:border-emerald-800 hover:shadow-sm transition-all flex items-center gap-4 text-left group"
                          >
                             <div className="w-10 h-10 bg-slate-50 dark:bg-slate-800 rounded-lg flex items-center justify-center font-bold text-slate-400 dark:text-slate-500 group-hover:text-emerald-600 dark:group-hover:text-emerald-400 group-hover:bg-emerald-50 dark:group-hover:bg-emerald-900/20 transition-colors relative overflow-hidden">
                                 <span className="relative z-10">{surah.number}</span>
                                 {percent === 100 && <div className="absolute inset-0 bg-emerald-100 dark:bg-emerald-900/40"></div>}
                             </div>
                             <div className="flex-1">
                                 <div className="flex justify-between items-center mb-1">
                                    <h3 className="font-bold text-slate-800 dark:text-slate-100">{surah.englishName}</h3>
                                    {surahProgress > 0 && (
                                        <span className="text-[10px] font-medium px-2 py-0.5 rounded-full bg-emerald-50 dark:bg-emerald-900/20 text-emerald-600 dark:text-emerald-400">
                                            {percent}%
                                        </span>
                                    )}
                                 </div>
                                 <p className="text-xs text-slate-500 dark:text-slate-400 mb-2">{surah.englishNameTranslation} • {surah.numberOfAyahs} {t.verses}</p>

                                 {/* Progress Bar */}
                                 <div className="h-1.5 w-full bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden">
                                     <div 
                                        className={`h-full rounded-full transition-all duration-500 ${percent === 100 ? 'bg-emerald-500' : 'bg-emerald-500/60'}`} 
                                        style={{ width: `${percent}%` }}
                                     ></div>
                                 </div>
                             </div>
                             <div className="text-right pl-2">
                                 <span className="font-arabic text-xl text-slate-700 dark:text-slate-200">{surah.name.replace('سُورَةُ ', '')}</span>
                             </div>
                          </button>
                      )})}
                  </div>
              )}
           </div>
        </div>
     );
  }

  // Calculate detail progress
  const currentSurahProgress = progress[activeSurah.number] || 0;
  const detailPercent = (currentSurahProgress / activeSurah.numberOfAyahs) * 100;

  // Render Detail
  return (
      <div className="h-full flex flex-col animate-fade-in bg-white dark:bg-slate-950 relative">
          <audio ref={audioRef} className="hidden" preload="auto" />

          {/* Header */}
          <div className="sticky top-0 z-20 bg-white/95 dark:bg-slate-950/95 backdrop-blur-sm transition-colors border-b border-slate-100 dark:border-slate-800">
              <div className="px-4 py-4 flex items-center justify-between">
                  <button 
                    onClick={handleBack}
                    className="w-10 h-10 rounded-full hover:bg-slate-100 dark:hover:bg-slate-900 flex items-center justify-center text-slate-600 dark:text-slate-300 transition-colors"
                  >
                      <ArrowLeft size={22} />
                  </button>
                  <div className="text-center">
                      <h2 className="font-bold text-slate-800 dark:text-slate-100">{activeSurah.englishName}</h2>
                      <p className="text-xs text-slate-500 dark:text-slate-400">{activeSurah.englishNameTranslation}</p>
                  </div>
                  <button 
                    onClick={() => setShowReciterList(true)}
                    className={`w-10 h-10 rounded-full hover:bg-slate-100 dark:hover:bg-slate-900 flex items-center justify-center transition-colors ${isPlaying || audioUrls.length > 0 ? 'text-emerald-600 dark:text-emerald-400' : 'text-slate-600 dark:text-slate-300'}`}
                  >
                      <Headphones size={22} />
                  </button>
              </div>
              {/* Sticky Progress Bar */}
              <div className="h-1 w-full bg-slate-100 dark:bg-slate-800">
                  <div 
                      className="h-full bg-emerald-500 transition-all duration-300 ease-out"
                      style={{ width: `${detailPercent}%` }}
                  ></div>
              </div>
          </div>

          <div ref={topRef} className={`flex-1 overflow-y-auto pb-32 scroll-smooth ${showReciterList ? 'overflow-hidden' : ''}`}>
               {/* Bismillah Header - Show for all except At-Tawbah (9) */}
               {activeSurah.number !== 9 && !loadingSurah && (
                   <div className="py-8 flex justify-center text-slate-800 dark:text-slate-100 opacity-80">
                       <p className="font-arabic text-3xl">بِسْمِ ٱللَّٰهِ ٱلرَّحْمَٰنِ ٱلرَّحِيمِ</p>
                   </div>
               )}

               {loadingSurah ? (
                   <div className="flex flex-col items-center justify-center py-32 space-y-4">
                       <Loader2 className="animate-spin text-emerald-600" size={32} />
                       <p className="text-sm text-slate-400">{t.loading}</p>
                   </div>
               ) : (
                   <div className="px-6 space-y-8 pb-10">
                       {ayahs.map((ayah, idx) => {
                           const isActive = currentAudioIndex === idx && isPlaying;
                           const isRead = ayah.number <= currentSurahProgress;

                           return (
                               <div 
                                   key={idx} 
                                   id={`ayah-${ayah.number}`}
                                   data-ayah-number={ayah.number}
                                   className={`ayah-item transition-all duration-500 ${isActive ? 'scale-[1.02]' : ''}`}
                               >
                                   {/* Arabic */}
                                   <div className={`w-full p-6 pb-8 rounded-2xl mb-4 border transition-colors duration-300 relative ${isActive ? 'bg-emerald-50 dark:bg-emerald-900/20 border-emerald-200 dark:border-emerald-800' : 'bg-slate-50 dark:bg-slate-900/40 border-slate-100 dark:border-slate-800/50'}`}>
                                       <p className={`text-right font-arabic text-3xl leading-[2.5] ${isActive ? 'text-emerald-800 dark:text-emerald-100' : 'text-slate-800 dark:text-slate-100'}`} dir="rtl">
                                           {ayah.arabic} 
                                           <span className={`inline-flex items-center justify-center w-8 h-8 mx-2 text-sm border rounded-full font-sans number-symbol align-middle transition-colors duration-500 ${isActive ? 'bg-emerald-100 dark:bg-emerald-800 text-emerald-700 dark:text-emerald-200 border-emerald-300 dark:border-emerald-700' : isRead ? 'bg-emerald-500 text-white border-emerald-500' : 'bg-white dark:bg-slate-800 text-emerald-600 dark:text-emerald-400 border-emerald-500/50'}`}>
                                               {isRead && !isActive ? <Check size={12} strokeWidth={3} /> : ayah.number}
                                           </span>
                                       </p>

                                       {/* Play Button for Ayah */}
                                       <div className="absolute bottom-4 left-4">
                                            <button
                                                onClick={() => playAyah(idx)}
                                                disabled={loadingAudio}
                                                className={`w-8 h-8 rounded-full flex items-center justify-center transition-all ${isActive ? 'bg-emerald-500 text-white shadow-lg shadow-emerald-500/30' : 'bg-white dark:bg-slate-800 text-slate-400 hover:text-emerald-600 dark:hover:text-emerald-400 shadow-sm border border-slate-200 dark:border-slate-700'}`}
                                            >
                                                {isActive ? <Pause size={14} className="fill-current" /> : <Play size={14} className="fill-current ml-0.5" />}
                                            </button>
                                       </div>
                                   </div>

                                   {/* Translation */}
                                   <div className="px-2">
                                       <p className={`leading-relaxed text-lg transition-colors ${isActive ? 'text-slate-800 dark:text-slate-200 font-medium' : 'text-slate-600 dark:text-slate-300'}`}>
                                           {ayah.translation}
                                       </p>
                                   </div>

                                   {idx < ayahs.length - 1 && (
                                       <div className="my-8 border-b border-slate-100 dark:border-slate-800/60 w-1/2 mx-auto"></div>
                                   )}
                               </div>
                           );
                       })}
                   </div>
               )}
          </div>

          {/* Audio Player Bar */}
          <div className="absolute bottom-0 left-0 right-0 bg-white dark:bg-slate-900 border-t border-slate-200 dark:border-slate-800 p-4 shadow-[0_-4px_10px_rgba(0,0,0,0.05)] z-30 transition-transform duration-300 flex items-center justify-between gap-4">
               <div className="flex flex-col min-w-0">
                   <span className="text-xs font-bold text-emerald-600 dark:text-emerald-400 uppercase tracking-wider">{t.playing}</span>
                   <span className="text-sm font-semibold text-slate-800 dark:text-slate-100 truncate">{activeReciter.name}</span>
               </div>

               <div className="flex items-center gap-2 md:gap-4">
                    <button 
                        onClick={cycleSpeed}
                        className="text-xs font-bold w-10 h-8 rounded-lg bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-300 hover:bg-emerald-100 dark:hover:bg-emerald-900/30 hover:text-emerald-600 dark:hover:text-emerald-400 transition-colors"
                        title="Playback Speed"
                    >
                        {playbackSpeed}x
                    </button>

                    <button 
                        onClick={toggleRepeat}
                        className={`w-8 h-8 flex items-center justify-center rounded-lg transition-colors ${repeatMode !== 'none' ? 'bg-emerald-100 text-emerald-600 dark:bg-emerald-900/30 dark:text-emerald-400' : 'text-slate-400 hover:text-slate-600 dark:hover:text-slate-300'}`}
                        title={repeatMode === 'one' ? 'Repeat Ayah' : repeatMode === 'all' ? 'Repeat Surah' : 'No Repeat'}
                    >
                        {repeatMode === 'one' ? <Repeat1 size={18} /> : <Repeat size={18} />}
                    </button>

                    <button 
                        onClick={() => setCurrentAudioIndex(prev => Math.max(0, prev - 1))}
                        className="text-slate-400 hover:text-slate-600 dark:hover:text-slate-200"
                        disabled={currentAudioIndex <= 0}
                    >
                        <SkipBack size={20} className="fill-current" />
                    </button>

                    <button 
                        onClick={togglePlay}
                        disabled={loadingAudio}
                        className="w-12 h-12 bg-emerald-600 hover:bg-emerald-700 text-white rounded-full flex items-center justify-center shadow-lg shadow-emerald-600/30 active:scale-95 transition-all"
                    >
                        {loadingAudio ? (
                            <Loader2 size={20} className="animate-spin" />
                        ) : isPlaying ? (
                            <Pause size={20} className="fill-current" />
                        ) : (
                            <Play size={20} className="fill-current ml-1" />
                        )}
                    </button>

                    <button 
                         onClick={() => setCurrentAudioIndex(prev => Math.min((audioUrls.length || ayahs.length) - 1, prev + 1))}
                         className="text-slate-400 hover:text-slate-600 dark:hover:text-slate-200"
                         disabled={currentAudioIndex >= (audioUrls.length || ayahs.length) - 1}
                    >
                        <SkipForward size={20} className="fill-current" />
                    </button>
               </div>
          </div>

          {/* Reciter Selection Modal */}
          {showReciterList && (
              <div className="absolute inset-0 z-40 bg-white dark:bg-slate-950 flex flex-col animate-fade-in">
                  <div className="p-4 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between bg-white dark:bg-slate-950">
                      <h3 className="font-bold text-lg text-slate-800 dark:text-slate-100">{t.selectReciter}</h3>
                      <button onClick={() => setShowReciterList(false)} className="p-2 bg-slate-100 dark:bg-slate-900 rounded-full text-slate-500 hover:text-slate-800 dark:hover:text-slate-200">
                          <X size={20} />
                      </button>
                  </div>
                  <div className="flex-1 overflow-y-auto p-4 space-y-2">
                      {reciters.length === 0 && <div className="text-center p-10"><Loader2 className="animate-spin mx-auto text-emerald-500" /></div>}
                      {reciters.map((reciter) => (
                          <button
                              key={reciter.identifier}
                              onClick={() => handleReciterChange(reciter)}
                              className={`w-full p-4 rounded-xl flex items-center justify-between text-left transition-all ${activeReciter.identifier === reciter.identifier ? 'bg-emerald-50 dark:bg-emerald-900/20 border border-emerald-200 dark:border-emerald-800' : 'bg-white dark:bg-slate-900 border border-slate-100 dark:border-slate-800 hover:border-emerald-200 dark:hover:border-emerald-800'}`}
                          >
                              <div>
                                  <p className={`font-semibold ${activeReciter.identifier === reciter.identifier ? 'text-emerald-700 dark:text-emerald-400' : 'text-slate-700 dark:text-slate-200'}`}>
                                      {reciter.englishName}
                                  </p>
                                  <p className="text-xs text-slate-400 dark:text-slate-500">{reciter.name}</p>
                              </div>
                              {activeReciter.identifier === reciter.identifier && <Check size={18} className="text-emerald-600" />}
                          </button>
                      ))}
                  </div>
              </div>
          )}
      </div>
  );
};

