export const generateProphetStory = async (prophetName: string, language: string = 'en'): Promise<ProphetStory | null> => {
  if (!apiKey) return null;
  const langPrompt = language === 'fr' ? 'French' : 'English';
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Tell me the detailed story of Prophet ${prophetName} AS. 
      Provide:
      1. A rich, engaging, and detailed biography/summary of their life and mission.
      2. The approximate historical period (e.g., "Approx. 2000 BCE").
      3. The geographical location of their mission.
      4. A list of key life events in chronological order.
      5. A list of miracles.
      6. Spiritual lessons derived from their life.
      7. Key Quranic references (Surah:Verse).

      Language: ${langPrompt}.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            name: { type: Type.STRING },
            arabicName: { type: Type.STRING },
            summary: { type: Type.STRING },
            period: { type: Type.STRING },
            location: { type: Type.STRING },
            keyEvents: { type: Type.ARRAY, items: { type: Type.STRING } },
            miracles: { type: Type.ARRAY, items: { type: Type.STRING } },
            lessons: { type: Type.ARRAY, items: { type: Type.STRING } },
            quranicReferences: { type: Type.ARRAY, items: { type: Type.STRING } },
          },
          required: ["name", "arabicName", "summary", "period", "location", "keyEvents", "miracles", "lessons", "quranicReferences"],
        },
      },
    });
    const data = JSON.parse(response.text || '{}');
    if (!data.name || !data.summary || !Array.isArray(data.miracles)) return null;
    return data as ProphetStory;
  } catch (error) { 
    console.error("Prophet Story Error:", error);
    return null; 
  }
};

export const findMosques = async (lat: number, lng: number, language: string = 'en'): Promise<{ text: string, places: PlaceResult[] }> => {
  if (!apiKey) return { text: "", places: [] };
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Find the best rated mosques nearby.`,
      config: {
        tools: [{ googleMaps: {} }],
        toolConfig: { retrievalConfig: { latLng: { latitude: lat, longitude: lng } } }
      },
    });
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const mapPlaces = chunks.filter((c: any) => c.maps).map((c: any) => ({
      title: c.maps.title,
      uri: c.maps.uri,
      snippet: c.maps.placeAnswerSources?.reviewSnippets?.[0]?.snippet,
      type: 'mosque'
    }));
    return { text: response.text || "", places: mapPlaces };
  } catch (error) { return { text: "", places: [] }; }
};

export const chatWithAi = async (message: string, history: any[], language: string = 'en'): Promise<string> => {
  if (!apiKey) return "API Key missing.";
  const langInstruction = language === 'fr' ? 'Reply in French.' : 'Reply in English.';
  try {
    const chat = ai.chats.create({
      model: 'gemini-3-flash-preview',
      config: {
        systemInstruction: `You are Sabildeen, a knowledgeable Islamic AI. Help with Duas, history, and spiritual advice. Be concise and warm. ${langInstruction}`
      }
    });
    const result = await chat.sendMessage({ message });
    return result.text || "No response from AI.";
  } catch (error) { return "Error connecting to AI."; }
};

export const checkHalalIngredients = async (base64Image: string, language: string = 'en'): Promise<HalalCheckResult | null> => {
  if (!apiKey) return null;
  const langPrompt = language === 'fr' ? 'French' : 'English';
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        {
          parts: [
            { inlineData: { mimeType: 'image/jpeg', data: base64Image } },
            { text: `Analyze the ingredient list in this image and determine if the product is Halal, Haram, or Doubtful according to Islamic dietary laws. Provide the result in ${langPrompt}.` }
          ]
        }
      ],
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            status: { type: Type.STRING, enum: ['halal', 'haram', 'doubtful'] },
            reason: { type: Type.STRING },
            concerns: { type: Type.ARRAY, items: { type: Type.STRING } },
          },
          required: ["status", "reason", "concerns"],
        },
      },
    });
    const data = JSON.parse(response.text || '{}');
    if (!data.status) return null;
    return data as HalalCheckResult;
  } catch (error) {
    console.error("Halal scan error:", error);
    return null;
  }
};

