                                 <div className="absolute bottom-1.5 flex gap-0.5">
                                     {day.events.length > 0 && (
                                         <div className={`w-1 h-1 rounded-full ${hasEid ? 'bg-amber-500' : 'bg-emerald-400'}`}></div>
