const Academy: React.FC<AcademyProps> = ({ onNavigate, language = 'en' }) => {
  const [activeQuiz, setActiveQuiz] = useState<QuizQuestion[] | null>(null);
  const [quizLoading, setQuizLoading] = useState(false);
  const [currentQuestion, setCurrentQuestion] = useState(0);
  const [score, setScore] = useState(0);
  const [showResult, setShowResult] = useState(false);
  const [selectedAnswer, setSelectedAnswer] = useState<number | null>(null);

  const t = {
    title: language === 'fr' ? 'Académie Sabildeen' : 'Sabildeen Academy',
    subtitle: language === 'fr' ? 'Apprenez, Mémorisez, Grandissez' : 'Learn, Memorize, Grow',
    start: language === 'fr' ? 'Commencer' : 'Start',
    quizTitle: language === 'fr' ? 'Test de Connaissances' : 'Knowledge Quiz',
    genQuiz: language === 'fr' ? 'Générer un Quiz' : 'Generate Quiz',
    next: language === 'fr' ? 'Suivant' : 'Next',
    finish: language === 'fr' ? 'Terminer' : 'Finish',
    score: language === 'fr' ? 'Votre Score' : 'Your Score',
    close: language === 'fr' ? 'Fermer' : 'Close',
    loading: language === 'fr' ? 'Préparation du quiz...' : 'Preparing quiz...',
    explanation: language === 'fr' ? 'Explication' : 'Explanation',
  };

  const startQuiz = async (trackId: string, title: string) => {
    setQuizLoading(true);
    let topic = title;
    let level = 'intermediate';

    if (trackId === 'new_muslim' || trackId === 'quiz-basics') {
       topic = 'Islamic Basics (5 Pillars, Wudu, Prayer)';
       level = 'beginner';
    } else if (trackId === 'kids' || trackId === 'quiz-kids') {
       topic = 'Prophets and Islamic Manners for Kids';
       level = 'child';
    } else if (trackId === 'stories') {
       topic = 'Lives of Prophets';
    }

    const questions = await generateQuiz(topic, level, language);
    setActiveQuiz(questions);
    setQuizLoading(false);
    setCurrentQuestion(0);
    setScore(0);
    setShowResult(false);
    setSelectedAnswer(null);
  };

  const handleAnswer = (index: number) => {
    if (selectedAnswer !== null) return;
    setSelectedAnswer(index);
    if (index === activeQuiz![currentQuestion].correctAnswer) {
      setScore(s => s + 1);
    }
  };

  const nextQuestion = () => {
    if (currentQuestion < activeQuiz!.length - 1) {
      setCurrentQuestion(c => c + 1);
      setSelectedAnswer(null);
    } else {
      setShowResult(true);
    }
  };

  const closeQuiz = () => {
    setActiveQuiz(null);
    setCurrentQuestion(0);
    setScore(0);
    setSelectedAnswer(null);
    setShowResult(false);
  };

  if (activeQuiz) {
    // Quiz View
    const question = activeQuiz[currentQuestion];
    return (
      <div className="h-full flex flex-col bg-slate-50 dark:bg-slate-950 animate-fade-in p-6">
