             <XCircle size={24} />
           </button>
        </div>

        {showResult ? (
          <div className="flex-1 flex flex-col items-center justify-center text-center space-y-6">
             <div className="w-32 h-32 bg-emerald-100 dark:bg-emerald-900/30 rounded-full flex items-center justify-center mb-4">
                <Star size={64} className="text-emerald-600 dark:text-emerald-400 fill-current" />
             </div>
             <div>
               <h3 className="text-2xl font-bold text-slate-800 dark:text-slate-100">{t.score}</h3>
               <p className="text-4xl font-bold text-emerald-600 dark:text-emerald-400 mt-2">{score} / {activeQuiz.length}</p>
             </div>
             <button 
               onClick={closeQuiz}
               className="bg-emerald-600 text-white px-8 py-3 rounded-full font-bold shadow-lg hover:bg-emerald-700 transition-all"
             >
               {t.close}
             </button>
          </div>
        ) : (
          <div className="flex-1 flex flex-col">
             <div className="mb-8">
               <div className="flex justify-between text-xs text-slate-400 mb-2 font-bold uppercase tracking-wider">
                 <span>Question {currentQuestion + 1}/{activeQuiz.length}</span>
                 <span>Score: {score}</span>
               </div>
               <div className="h-2 bg-slate-200 dark:bg-slate-800 rounded-full overflow-hidden">
                 <div className="h-full bg-emerald-500 transition-all duration-300" style={{ width: `${((currentQuestion + 1) / activeQuiz.length) * 100}%` }}></div>
               </div>
             </div>

             <h3 className="text-xl font-bold text-slate-800 dark:text-slate-100 mb-6 leading-relaxed">
               {question.question}
             </h3>

             <div className="space-y-3 flex-1">
               {question.options.map((opt, idx) => {
                 let btnClass = "bg-white dark:bg-slate-900 border-slate-200 dark:border-slate-800 hover:border-emerald-500 dark:hover:border-emerald-500";

                 if (selectedAnswer !== null) {
                    if (idx === question.correctAnswer) {
                        btnClass = "bg-emerald-100 dark:bg-emerald-900/40 border-emerald-500 text-emerald-800 dark:text-emerald-200";
                    } else if (idx === selectedAnswer) {
                        btnClass = "bg-red-100 dark:bg-red-900/40 border-red-500 text-red-800 dark:text-red-200";
                    } else {
                        btnClass = "opacity-50 bg-slate-50 dark:bg-slate-900 border-slate-200 dark:border-slate-800";
                    }
                 }

                 return (
                   <button
                     key={idx}
                     onClick={() => handleAnswer(idx)}
                     disabled={selectedAnswer !== null}
                     className={`w-full p-4 rounded-xl border-2 text-left transition-all font-medium ${btnClass}`}
                   >
                     {opt}
                   </button>
                 );
               })}
             </div>

             {selectedAnswer !== null && (
               <div className="mt-6 animate-fade-in-up">
                 <div className="bg-slate-50 dark:bg-slate-900 p-4 rounded-xl border border-slate-100 dark:border-slate-800 mb-4">
                    <p className="text-xs font-bold text-slate-400 uppercase mb-1">{t.explanation}</p>
                    <p className="text-sm text-slate-700 dark:text-slate-300">{question.explanation}</p>
                 </div>
                 <button 
                   onClick={nextQuestion}
                   className="w-full bg-emerald-600 text-white py-3 rounded-xl font-bold hover:bg-emerald-700 transition-colors flex items-center justify-center gap-2"
                 >
                   {currentQuestion < activeQuiz.length - 1 ? t.next : t.finish} <ArrowRight size={18} />
                 </button>
               </div>
             )}
          </div>
        )}
      </div>
    );
  }

  // Dashboard View
  return (
    <div className="h-full bg-slate-50 dark:bg-slate-950 animate-fade-in flex flex-col">
      <header className="p-6 pb-2">
        <div className="flex items-center gap-3 mb-2">
