              <p className="text-xs font-medium text-slate-500 dark:text-slate-400 uppercase tracking-wider">{t.subtitle}</p>
           </div>
        </div>
      </header>

      <div className="flex-1 overflow-y-auto px-6 pb-24 space-y-6">
         {/* Welcome Banner */}
         <div className="bg-slate-900 dark:bg-slate-800 rounded-3xl p-6 text-white relative overflow-hidden shadow-xl">
            <div className="absolute top-0 right-0 w-40 h-40 bg-white/10 rounded-full blur-3xl -mr-10 -mt-10"></div>
            <div className="relative z-10">
               <h2 className="text-xl font-bold mb-2">{language === 'fr' ? 'Continuez votre apprentissage' : 'Continue your journey'}</h2>
               <p className="text-slate-300 text-sm mb-4 max-w-[80%]">
                 {language === 'fr' 
                   ? "Approfondissez vos connaissances du Coran et de la Sunnah aujourd'hui." 
                   : "Deepen your knowledge of the Quran and Sunnah today."}
               </p>
               <button 
                 onClick={() => startQuiz('general', 'General Islamic Knowledge')}
                 disabled={quizLoading}
                 className="bg-emerald-500 hover:bg-emerald-600 text-white px-5 py-2 rounded-full text-sm font-bold transition-colors flex items-center gap-2"
               >
                 {quizLoading ? <Loader2 size={16} className="animate-spin" /> : <Brain size={16} />}
                 {t.genQuiz}
               </button>
            </div>
         </div>

         <div className="grid gap-4">
            {ACADEMY_TRACKS.map((track) => {
               const Icon = track.icon;
               const isQuizTrack = track.target.startsWith('quiz-');

               return (
                 <button
                   key={track.id}
                   onClick={() => isQuizTrack ? startQuiz(track.target, track.title[language as 'en'|'fr']) : onNavigate(track.target)}
                   className="group relative overflow-hidden bg-white dark:bg-slate-900 rounded-3xl p-5 border border-slate-100 dark:border-slate-800 shadow-sm hover:shadow-md transition-all active:scale-[0.98] text-left"
