            {/* Quick Actions Grid (Bento Style) */}
            <div className="grid grid-cols-2 gap-4">
              <button onClick={() => setActiveTab('tasbih')} className="relative group overflow-hidden bg-gradient-to-br from-blue-500 to-blue-600 p-5 rounded-[1.5rem] text-white shadow-lg shadow-blue-500/20 transition-all hover:scale-[1.02] active:scale-95 text-left h-32 flex flex-col justify-between">
                <div className="absolute top-0 right-0 w-24 h-24 bg-white/10 rounded-full -mr-10 -mt-10 blur-xl group-hover:bg-white/20 transition-colors"></div>
                <div className="bg-white/20 w-10 h-10 rounded-xl flex items-center justify-center backdrop-blur-sm">
                  <Hand size={20} className="text-white" />
                </div>
                <div>
                  <span className="block font-bold text-lg">{t.tasbihTitle}</span>
                  <span className="text-xs text-blue-100 opacity-80 font-medium">Digital Dhikr</span>
                </div>
              </button>

              <button onClick={() => setActiveTab('qibla')} className="relative group overflow-hidden bg-gradient-to-br from-purple-500 to-purple-600 p-5 rounded-[1.5rem] text-white shadow-lg shadow-purple-500/20 transition-all hover:scale-[1.02] active:scale-95 text-left h-32 flex flex-col justify-between">
                <div className="absolute top-0 right-0 w-24 h-24 bg-white/10 rounded-full -mr-10 -mt-10 blur-xl group-hover:bg-white/20 transition-colors"></div>
                <div className="bg-white/20 w-10 h-10 rounded-xl flex items-center justify-center backdrop-blur-sm">
                  <Compass size={20} className="text-white" />
                </div>
                <div>
                  <span className="block font-bold text-lg">{t.qiblaTitle}</span>
                  <span className="text-xs text-purple-100 opacity-80 font-medium">Find Direction</span>
                </div>
              </button>

              <button onClick={() => setActiveTab('academy')} className="relative group overflow-hidden bg-white dark:bg-slate-900 border border-slate-100 dark:border-slate-800 p-5 rounded-[1.5rem] shadow-sm transition-all hover:border-emerald-200 dark:hover:border-emerald-900 active:scale-95 text-left flex items-center gap-4">
                <div className="bg-emerald-100 dark:bg-emerald-900/30 w-12 h-12 rounded-2xl flex items-center justify-center text-emerald-600 dark:text-emerald-400">
                  <GraduationCap size={22} />
                </div>
                <div>
                  <span className="block font-bold text-slate-800 dark:text-slate-100">{t.academy}</span>
                  <span className="text-xs text-slate-500 dark:text-slate-400">Learn & Grow</span>
                </div>
              </button>

              <button onClick={() => setActiveTab('mosques')} className="relative group overflow-hidden bg-white dark:bg-slate-900 border border-slate-100 dark:border-slate-800 p-5 rounded-[1.5rem] shadow-sm transition-all hover:border-blue-200 dark:hover:border-blue-900 active:scale-95 text-left flex items-center gap-4">
                <div className="bg-blue-100 dark:bg-blue-900/30 w-12 h-12 rounded-2xl flex items-center justify-center text-blue-600 dark:text-blue-400">
                  <MapPin size={22} />
                </div>
                <div>
                  <span className="block font-bold text-slate-800 dark:text-slate-100">{t.mosquesTitle}</span>
                  <span className="text-xs text-slate-500 dark:text-slate-400">Find Nearby</span>
                </div>
              </button>
            </div>

            <div className="grid gap-6">
              <section>
                <div className="flex items-center justify-between mb-3 px-1">
                  <div className="flex items-center gap-2">
                    <div className="w-6 h-6 bg-emerald-100 dark:bg-emerald-900/30 rounded-lg flex items-center justify-center text-emerald-600 dark:text-emerald-400">
                      <BookOpen size={14} />
                    </div>
                    <h2 className="text-sm font-bold text-slate-700 dark:text-slate-200 uppercase tracking-wide">{t.dailyInspo}</h2>
                  </div>
                </div>
                <DailyVerseCard language={language} />
              </section>

              <section>
                <div className="flex items-center justify-between mb-3 px-1">
                  <div className="flex items-center gap-2">
                    <div className="w-6 h-6 bg-blue-100 dark:bg-blue-900/30 rounded-lg flex items-center justify-center text-blue-600 dark:text-blue-400">
                      <Quote size={14} />
                    </div>
                    <h2 className="text-sm font-bold text-slate-700 dark:text-slate-200 uppercase tracking-wide">{t.dailyHadith}</h2>
                  </div>
                </div>
                <DailyHadithCard language={language} />
              </section>
            </div>
          </div>
        );
      case 'prayer-catalog': 
        return <PrayerCatalog prayerData={prayerData} loading={loadingPrayers} language={language} onBack={() => setActiveTab('home')} />;
      case 'quran': return <QuranReader language={language} />;
      case 'mosques': return <MosqueFinder location={location} language={language} />;
      case 'chat': return <ChatInterface language={language} />;
      case 'tasbih': return <TasbihCounter onBack={() => setActiveTab('home')} language={language} />;
      case 'qibla': return <QiblaFinder location={location} onBack={() => setActiveTab('home')} language={language} />;
      case 'stories': return <ProphetStories onBack={() => setActiveTab('academy')} language={language} />;
      case 'hadith': return <HadithCollection onBack={() => setActiveTab('academy')} />;
      case 'calendar': return <HijriCalendar onBack={() => setActiveTab('home')} language={language} />;
      case 'hifz': return (
        <div className="h-full flex flex-col bg-slate-50 dark:bg-slate-950 animate-fade-in pb-24">
           <div className="p-6 sticky top-0 bg-white/95 dark:bg-slate-950/95 backdrop-blur-sm z-20 border-b border-slate-100 dark:border-slate-800 flex items-center gap-4">
             <button onClick={() => setActiveTab('academy')} className="p-2 -ml-2 rounded-full hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors">
               <Settings className="rotate-90" size={20} /> {/* Using rotate as back arrow replacement if ArrowLeft unavailable in context or reuse icon */}
             </button>
             <h1 className="text-xl font-bold text-slate-800 dark:text-slate-100">Hifz Tracker</h1>
           </div>
           <div className="p-6">
             <HifzTracker language={language} />
           </div>
        </div>
      );
      case 'academy': return <Academy onNavigate={(tab) => setActiveTab(tab)} language={language} />;
      default: return null;
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 dark:bg-slate-950 transition-colors duration-500 font-sans selection:bg-emerald-100 dark:selection:bg-emerald-900">
      <div className="max-w-md mx-auto min-h-screen bg-white dark:bg-slate-950 relative shadow-2xl shadow-slate-200/50 dark:shadow-none overflow-hidden">
        <main className="min-h-screen relative z-10">
          <div className="p-6 min-h-screen">
             {renderContent()}
          </div>
        </main>

        {/* Navigation Wrapper */}
        <Navigation activeTab={['stories', 'hadith', 'hifz', 'academy'].includes(activeTab) ? 'academy' : (activeTab === 'prayer-catalog' ? 'prayer-catalog' : activeTab)} setActiveTab={setActiveTab} language={language} />

        <SettingsModal 
          isOpen={showSettings} onClose={() => setShowSettings(false)}
          darkMode={darkMode} toggleDarkMode={() => setDarkMode(!darkMode)}
          language={language} setLanguage={setLanguage}
          calculationMethod={calculationMethod} setCalculationMethod={setCalculationMethod}
          prayerOffsets={{}} setPrayerOffset={() => {}} notifications={true} toggleNotifications={() => {}}
        />
      </div>
    </div>
  );
};

export default App;
